package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testIsNullStringSetWhenNullStringIsNull() throws Exception {
        // Create CSVFormat instance with nullString == null
        CSVFormat format = CSVFormat.DEFAULT.withNullString(null);

        // Use reflection to get the private field nullString
        Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);

        // Assert field value is null
        assertNull(nullStringField.get(format));

        // Call isNullStringSet and assert false
        assertFalse(format.isNullStringSet());
    }

    @Test
    void testIsNullStringSetWhenNullStringIsSet() throws Exception {
        // Create CSVFormat instance with a non-null nullString
        CSVFormat format = CSVFormat.DEFAULT.withNullString("NULL");

        // Use reflection to get the private field nullString
        Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);

        // Assert field value is "NULL"
        assertEquals("NULL", nullStringField.get(format));

        // Call isNullStringSet and assert true
        assertTrue(format.isNullStringSet());
    }
}
